<template>
	<view class="container">
		<view class="header">
			<text class="title">支部新闻</text>
		</view>

		<!-- 新闻列表（与公告页同款） -->
		<view class="news-list">
			<view 
				class="news-item" 
				v-for="(item, index) in newsList" 
				:key="item.id"
				@click="handleViewDetail(item)"
			>
				<view class="item-header">
					<text class="item-title">{{ item.title }}</text>
					<text class="item-time">{{ formatTime(item.publishedAt || item.createdAt) }}</text>
				</view>
			</view>

			<!-- 空状态 -->
			<view class="empty-state" v-if="newsList.length === 0 && !loading">
				<text>暂无新闻</text>
			</view>
		</view>

		<!-- 加载状态 -->
		<view class="loading" v-if="loading">
			<text>加载中...</text>
		</view>
	</view>
</template>

<script setup>
import { ref, onMounted } from 'vue'
import { toAbsoluteUrl } from '@/utils/api.js'
import { onShow, onPullDownRefresh, onReachBottom } from '@dcloudio/uni-app'
import { requestWithAuth } from '@/utils/auth.js'

const newsList = ref([])
const loading = ref(false)
const hasMore = ref(true)
const currentPage = ref(1)
const pageSize = ref(10)

const formatTime = (timeStr) => {
	if (!timeStr) return ''
	try {
		const date = new Date(timeStr)
		const now = new Date()
		const diff = now - date
		if (diff < 60000) return '刚刚'
		if (diff < 3600000) return Math.floor(diff / 60000) + '分钟前'
		if (diff < 86400000) return Math.floor(diff / 3600000) + '小时前'
		if (diff < 604800000) return Math.floor(diff / 86400000) + '天前'
		return date.toLocaleDateString('zh-CN')
	} catch { return timeStr }
}

const handleViewDetail = (item) => {
	uni.navigateTo({ url: `/pages/home/news-detail?id=${item.id}&title=${encodeURIComponent(item.title)}` })
}

const loadData = async () => {
	if (loading.value) return
	loading.value = true
	try {
		const params = { page: currentPage.value, size: pageSize.value }
		const res = await requestWithAuth({ url: '/news/user', method: 'GET', data: params })
		if (res.statusCode === 200 && res.data?.code === 200) {
			const newData = res.data.data || []
			if (currentPage.value === 1) newsList.value = newData
			else newsList.value.push(...newData)
			hasMore.value = newData.length === pageSize.value
		} else if (res.statusCode === 401 || res.data?.code === 401) {
			uni.showToast({ title: '请先登录', icon: 'none' })
			setTimeout(() => uni.navigateTo({ url: '/pages/my/login/login' }), 600)
		}
	} catch (e) {
		uni.showToast({ title: '加载失败', icon: 'none' })
	} finally {
		loading.value = false
	}
}

const onRefresh = () => {
	currentPage.value = 1
	newsList.value = []
	hasMore.value = true
	loadData()
}

onMounted(loadData)
onShow(onRefresh)
onPullDownRefresh(() => { onRefresh(); setTimeout(() => uni.stopPullDownRefresh(), 1000) })
onReachBottom(() => { if (hasMore.value && !loading.value) { currentPage.value++; loadData() } })
</script>

<style lang="scss" scoped>
.container { padding: 20rpx; background-color: #f5f5f5; min-height: 100vh; }
.header { text-align: center; margin-bottom: 30rpx; }
.header .title { font-size: 36rpx; font-weight: bold; color: #333; }
.news-list {
	.news-item { background: #fff; border-radius: 10rpx; padding: 30rpx; margin-bottom: 20rpx; box-shadow: 0 2rpx 10rpx rgba(0,0,0,0.1); }
	.item-header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 20rpx; }
	.item-title { font-size: 32rpx; font-weight: bold; color: #333; flex: 1; margin-right: 20rpx; }
	.item-time { font-size: 24rpx; color: #999; white-space: nowrap; }
}
.empty-state { text-align: center; padding: 100rpx 0; color: #999; font-size: 28rpx; }
.loading { text-align: center; padding: 40rpx 0; color: #999; font-size: 28rpx; }
</style>
